import{_ as e,o as a,c as o,a4 as r}from"./chunks/framework.BybBnFXO.js";const p=JSON.parse('{"title":"Transition-Metal Ion Coloration","description":"","frontmatter":{"title":"Transition-Metal Ion Coloration","colorCause":"transition-metal"},"headers":[],"relativePath":"color-causes/transition-metal.md","filePath":"color-causes/transition-metal.md","lastUpdated":1784176423000}'),d={name:"color-causes/transition-metal.md"};function n(i,t,l,s,h,c){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="transition-metal-ion-coloration" tabindex="-1">Transition-Metal Ion Coloration <a class="header-anchor" href="#transition-metal-ion-coloration" aria-label="Permalink to &quot;Transition-Metal Ion Coloration&quot;">вЂ‹</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">вЂ‹</a></h2><p>Transition-metal ions (Cr, Fe, Mn, Co, Ni, V, Cu, Ti) have partially filled d or f orbitals. When substituted into a host lattice, crystal-field splitting creates d-d absorption bands in the visible spectrum. The unabsorbed wavelengths produce the gem&#39;s color. This is the dominant cause of color in gemstones вЂ” roughly 70% of colored gems owe their hue to it.</p><h2 id="mechanism" tabindex="-1">Mechanism <a class="header-anchor" href="#mechanism" aria-label="Permalink to &quot;Mechanism&quot;">вЂ‹</a></h2><p><strong>Crystal-field theory</strong>: electrostatic field from coordinating anions (OВІвЃ», OHвЃ», FвЃ») lifts the degeneracy of the d-orbitals. Transitions between split levels absorb specific photon wavelengths. Coordination geometry (octahedral vs tetrahedral), bond length, and bond angles determine the energy gap and therefore the absorbed wavelength and resulting color.</p><h2 id="example-gemstones" tabindex="-1">Example Gemstones <a class="header-anchor" href="#example-gemstones" aria-label="Permalink to &quot;Example Gemstones&quot;">вЂ‹</a></h2><table tabindex="0"><thead><tr><th>Gem</th><th>Element</th><th>Host</th><th>Color</th></tr></thead><tbody><tr><td>Ruby / зєўе®ќзџі</td><td>CrВівЃє</td><td>Alв‚‚Oв‚ѓ</td><td>red</td></tr><tr><td>Emerald / зҐ–жЇЌз»ї</td><td>CrВівЃє / VВівЃє</td><td>Beв‚ѓAlв‚‚Siв‚†Oв‚Ѓв‚€</td><td>green</td></tr><tr><td>Sapphire (blue) / и“ќе®ќзџі</td><td>FeВІвЃєвЂ“TiвЃґвЃє</td><td>Alв‚‚Oв‚ѓ</td><td>blue</td></tr><tr><td>Aquamarine / жµ·и“ќе®ќ</td><td>FeВІвЃє</td><td>Beв‚ѓAlв‚‚Siв‚†Oв‚Ѓв‚€</td><td>blue</td></tr><tr><td>Peridot / ж©„ж¦„зџі</td><td>FeВІвЃє</td><td>(Mg,Fe)в‚‚SiOв‚„</td><td>olive-green</td></tr><tr><td>Tsavorite / жІ™еј—иЋ±</td><td>VВівЃє / CrВівЃє</td><td>Caв‚ѓAlв‚‚Siв‚ѓOв‚Ѓв‚‚</td><td>green</td></tr><tr><td>Alexandrite / дєљеЋ†е±±е¤§зџі</td><td>CrВівЃє</td><td>BeAlв‚‚Oв‚„</td><td>green / red (color-change)</td></tr><tr><td>Rhodonite / и”·и–‡иѕ‰зџі</td><td>MnВІвЃє</td><td>MnSiOв‚ѓ</td><td>pink</td></tr><tr><td>Rhodochrosite / иЏ±й”°зџї</td><td>MnВІвЃє</td><td>MnCOв‚ѓ</td><td>rose-pink</td></tr></tbody></table><p><em>See the <a href="./intro.html">color cause overview</a>.</em></p>',8)])])}const u=e(d,[["render",n]]);export{p as __pageData,u as default};
